    .input(z.object({ name: z.string().optional() }).optional())
    .query(({ input }) => {
      const name = input?.name ?? "world";
      return { greeting: `Hello, ${name}!` };
    }),
});

export type AppRouter = typeof appRouter;

const server = createHTTPServer({
  middleware: cors({
    origin: "http://localhost:3000",
    methods: ["GET", "POST", "OPTIONS"],
    allowedHeaders: ["Content-Type", "trpc-batch-mode"],
    credentials: true,
  }),
  router: appRouter,
  createContext() { return {}; },
});

server.listen(4000);
console.log("tRPC server listening on http://localhost:4000");
```

## Verified behaviour

| Test | Result |
|------|--------|
| `GET /hello?input={}` | `{"result":{"data":{"greeting":"Hello, world!"}}}` |
| `GET /hello?input={"name":"tRPC"}` | `{"result":{"data":{"greeting":"Hello, tRPC!"}}}` |
| `OPTIONS` preflight from `http://localhost:3000` | `204 No Content` with full CORS headers |

CORS preflight returns:
- `Access-Control-Allow-Origin: http://localhost:3000`
- `Access-Control-Allow-Credentials: true`
- `Access-Control-Allow-Methods: GET,POST,OPTIONS`
- `Access-Control-Allow-Headers: Content-Type,trpc-batch-mode`

